#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    cin >> n;
    string bin_str = bitset<32>(n).to_string();
    int start = 0, end = bin_str.size() - 1;
    while (start < end && bin_str[start] == '0') start++;
    while (start < end && bin_str[end] == '0') end--;
    bool is_palindrome = true;
    for (; start < end; start++, end--)
        if (bin_str[start] != bin_str[end]) {
            is_palindrome = false;
            break;
        }
    cout << (is_palindrome ? 1 : 0) << endl;
    return 0;
}
